    "fields": {
      "summary": "Build Testing agent (writes \u0026 runs tests, loops back on fail)",
      "description": {
        "content": [
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Goal",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "Given a PR opened by the Junior Dev agent, write dedicated tests, run them, and on failure hand work back to the Junior agent.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Deliverables",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "content": [
                  {
                    "content": [
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": "agents/testing/prompt.md",
                        "type": "text"
                      },
                      {
                        "text": ".",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": "agents/testing/README.md",
                        "type": "text"
