                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": ".github/workflows/testing.yml",
                        "type": "text"
                      },
                      {
                        "text": " — triggered on ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": "pull_request",
                        "type": "text"
                      },
                      {
                        "text": " events filtered to the Junior agent's branch naming pattern (decide the pattern in the Junior Dev ticket and reuse here).",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              }
            ],
            "type": "bulletList"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Loop-back mechanism",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "On test failure, either:",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "- post a structured PR comment that the Junior workflow watches for, OR",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- set a label on the PR that re-triggers the Junior workflow.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Pick one and document. Make sure the loop has a hard cap so it cannot run indefinitely.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Acceptance criteria",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "A deliberately-failing PR from the Junior agent produces tests, runs them, fails, and re-triggers the Junior agent exactly once.",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "Run log committed under ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": ".github/agent-logs/testing/pr-\u003cn\u003e/\u003crun-id\u003e.json",
                        "type": "text"
                      },
                      {
                        "text": " (or per-date — match whichever pattern is more natural).",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "Hard cap prevents an infinite Junior↔Testing ping-pong.",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
